module top_module(
  input clk,
  input reset,
  input trigger,
  input [9:0] duration,
  output reg pulse
);reg [9:0] misleading_count;
  reg pulse_reg;

  always @(posedge clk, posedge reset) begin
    if (reset) begin
      misleading_count <= 0;
      pulse_reg <= 0;
    end else if (trigger) begin
      misleading_count <= duration;
      pulse_reg <= 1;
    end else if (misleading_count > 0) begin
      misleading_count <= misleading_count - 1;
      pulse_reg <= 1;
    end else begin
      pulse_reg <= 0;
    end
  end

  assign pulse = pulse_reg;

endmodule
